mapper.select:
/* com.educare.edu.comn.mapper.LectureTimeMapper.selectByPk */
	select a.* 
	,(select title from t_lecture_mov where idx = a.mv_idx) mv_nm
	,(select sub_nm from t_lecture_subject where sub_seq = a.sub_seq) sub_nm
	from t_lecture_time a where a.edu_seq=#{eduSeq} and a.time_seq=#{timeSeq}

/* com.educare.edu.comn.mapper.LectureTimeMapper.selectByEduSeq */
	/** 시간표 조회 */
	select a.* 
	,(select room_nm from t_lecture_room where room_seq = a.room_seq) room_nm
	,(select title from t_lecture_mov where idx = a.mv_idx) mv_nm
	from t_lecture_time a 
	where a.edu_seq=#{eduSeq} 
	order by a.edu_dt,a.start_tm,a.time_seq

mapper.update:
/* com.educare.edu.comn.mapper.LectureTimeMapper.updateAllInstrNm */
	/** 시간강사이름 전부 변경 */
	update t_lecture_time 
	set instr_nm = #{instrNm}
	where edu_seq = #{eduSeq}

mapper.insert:
/* com.educare.edu.comn.mapper.LectureTimeMapper.insertByPk */


		select COALESCE(max(time_seq),0)+1 from t_lecture_time where edu_seq = #{eduSeq}


		select #{timeSeq}


	insert into t_lecture_time (
		edu_seq		,sub_seq		,time_seq	
		,edu_dt		,start_tm		,end_tm		,description	,instr_nm
		,check_id	,check_nm		,status		,class_how
		,url		,free_view		,mv_idx		,url_pw
		,room_seq	,ncs_nm
	) values (
		#{eduSeq}	,#{subSeq}	 	,#{timeSeq}	
		,#{eduDt}	,#{startTm}		,#{endTm}	,#{description}	,#{instrNm}
		,#{checkId}	,#{checkNm}		,#{status}	,#{classHow}	
		,#{url}		,#{freeView}	,#{mvIdx}	,#{urlPw}
		,#{roomSeq}	,#{ncsNm}
	)

mapper.update:
/* com.educare.edu.comn.mapper.LectureTimeMapper.updateByPk */
	update t_lecture_time
	set status = 1
	 		,edu_dt 		= #{eduDt} 
	 	,start_tm 		= #{startTm} 
	 		,end_tm 		= #{endTm} 
	 		,class_how 		= #{classHow}
	 ,description 	= #{description} 
	 		,check_id 		= #{checkId} 
	 		,room_seq		= #{roomSeq} 
	 		,ncs_nm 		= #{ncsNm} 
	 	,check_nm 		= #{checkNm} 
	 		,url 			= #{url} 
	 		,url_pw 		= #{urlPw} 
	 			,mv_idx 		= #{mvIdx} 
	where edu_seq = #{eduSeq} and time_seq = #{timeSeq}

mapper.select:
/* com.educare.edu.comn.mapper.LectureTimeMapper.selectByParam */
	select * from t_lecture_time
	where edu_seq = #{eduSeq}

		and edu_dt = #{eduDt}

/* com.educare.edu.comn.mapper.LectureTimeMapper.selectByDt */
	select a.* 
	,(select edu_nm from t_lecture where edu_seq = a.edu_seq) edu_nm
	,(select room_nm from t_lecture_room where room_seq = a.room_seq) room_nm
	from t_lecture_time a
	where 1=1
	and (
		a.edu_dt between #{srchStartDt} and #{srchEndDt}
	)
